import React from "react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion"; // ✅ ใช้ Framer Motion
import "../App.css";

const Home = () => {
  const navigate = useNavigate();

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center">
      {/* ✅ เพิ่มโคมไฟ */}
      <div className="lantern-container">
        {[...Array(5)].map((_, index) => (
          <motion.div
            key={index}
            src="/light14.svg" // ✅ ใช้ไฟล์โคมไฟที่เพิ่มเข้าไป
            alt="lantern"
            className="lantern"
            animate={{
              x: index % 2 === 0 ? [-10, 10, -10] : [10, -10, 10], // ✅ ทำให้ขยับซ้าย-ขวาแบบสลับกัน
            }}
            transition={{
              duration: 2,
              repeat: Infinity,
              ease: "easeInOut",
            }}
          />
        ))}
      </div>

      {/* ✅ เนื้อหาหน้า Home */}
      <div className="home-container">
        <h1 className="text-5xl font-bold text-pink-600 mb-4 font-Phudu">
          Capturing | Booth
        </h1>

        <h4 className="text-lg text-gray-700 mb-6">
          Welcome to Capturing! Photobooth! Lumen & LifeVoyage.
        </h4>

        <img src="/photobooth1.png" alt="photobooth strip" className="photobooth-strip" />

        <button onClick={() => navigate("/welcome")} className="start-button">
          START
        </button>
        <footer className="mt-8 text-sm text-gray-600 text-center font-kanit">
          <p>Version 1.0.3</p>
        </footer>
      </div>
    </div>
  );
};

export default Home;
